// src/components/DashboardAluno.jsx
import React, { useState, useEffect } from "react";
import axios from "axios";
import { useAuth } from "../context/AuthContext";
import { format, parseISO, isAfter } from "date-fns";

export default function DashboardAluno() {
  const { user } = useAuth();
  const [solicitacoes, setSolicitacoes] = useState([]);
  const [agendamentos, setAgendamentos] = useState([]);
  const [atendidos, setAtendidos] = useState([]);

  useEffect(() => {
    async function loadData() {
      try {
        // 1) Minhas solicitações
        const solRes = await axios.get("/api/solicitacoes/meus");
        // 2) Meus agendamentos
        const ageRes = await axios.get("/api/agendamentos/meus");

        setSolicitacoes(solRes.data);
        setAgendamentos(ageRes.data);

        // 3) Agendamentos atendidos: vamos considerar tudo que NÃO é 'Novo'
        const atendidosList = ageRes.data.filter(
          ag => ag.status && ag.status !== "Novo"
        );
        setAtendidos(atendidosList);
      } catch (err) {
        console.error("Erro ao carregar dashboard:", err.response?.data || err.message);
      }
    }
    loadData();
  }, []);

  // Contadores
  const pendentesCount = solicitacoes.filter(s => s.status === "Pendente" || s.status === "Solicitado").length;
  const proximosCount = agendamentos.filter(ag => {
    // considera data futura ou hoje
    return isAfter(parseISO(ag.data), new Date()) || format(parseISO(ag.data), "yyyy-MM-dd") === format(new Date(), "yyyy-MM-dd");
  }).length;
  const atendidosCount = atendidos.length;

  // Pega os 3 últimos de cada lista
  const ultimasSolic = [...solicitacoes]
    .sort((a,b) => new Date(b.data) - new Date(a.data))
    .slice(0,3);
  const ultimosAtend = [...atendidos]
    .sort((a,b) => new Date(b.data) - new Date(a.data))
    .slice(0,3);

  return (
    <div className="max-w-3xl mx-auto py-10 px-4">
      <h1 className="text-3xl font-bold mb-8">
        Olá, {user?.nome?.split(" ")[0] || "Aluno"}!
      </h1>

      {/* Resumo */}
      <div className="bg-blue-100 rounded-2xl shadow p-8 mb-8">
        <div className="text-lg font-semibold mb-4">Resumo</div>
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
          <div className="bg-white rounded-xl p-4 shadow text-center">
            <div className="font-bold text-2xl text-[#3172C0]">{pendentesCount}</div>
            <div className="text-gray-600">Solicitações Pendentes</div>
          </div>
          <div className="bg-white rounded-xl p-4 shadow text-center">
            <div className="font-bold text-2xl text-[#3172C0]">{proximosCount}</div>
            <div className="text-gray-600">Agendamentos Próximos</div>
          </div>
          <div className="bg-white rounded-xl p-4 shadow text-center">
            <div className="font-bold text-2xl text-[#3172C0]">{atendidosCount}</div>
            <div className="text-gray-600">Atendimentos Realizados</div>
          </div>
        </div>
      </div>

      {/* Últimas Solicitações */}
      <div className="bg-white rounded-2xl shadow p-6 mb-8">
        <h2 className="text-lg font-bold mb-4">Últimas Solicitações</h2>
        <ul className="space-y-3">
          {ultimasSolic.map(s => (
            <li
              key={s.id}
              className="flex justify-between items-center bg-gray-50 rounded-xl px-5 py-3 shadow-sm"
            >
              <span className="text-gray-800 font-medium">
                {format(parseISO(s.data), "dd/MM/yyyy")}
              </span>
              <span
                className={`px-4 py-1 rounded-full text-sm font-semibold ${
                  s.status === "Aprovada"
                    ? "bg-green-100 text-green-800"
                    : "bg-yellow-100 text-yellow-800"
                }`}
              >
                {s.status}
              </span>
            </li>
          ))}
        </ul>
      </div>

      {/* Últimos Atendimentos */}
      <div className="bg-white rounded-2xl shadow p-6">
        <h2 className="text-lg font-bold mb-4">Atendimentos Concluídos</h2>
        <ul className="space-y-3">
          {ultimosAtend.map(a => (
            <li
              key={a.id}
              className="flex justify-between items-center bg-gray-50 rounded-xl px-5 py-3 shadow-sm"
            >
              <span className="text-gray-800 font-medium">
                {format(parseISO(a.data), "dd/MM/yyyy")}
              </span>
              <span className="text-gray-600">{a.disciplinaNome}</span>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
}
